import LRUCache from"./structs/LRUCache.js";import{fromKey,getKey}from"./tilecoord.js";class TileCache extends LRUCache{expireCache(e){for(;this.canExpireCache();){const t=this.peekLast();if(t.getKey()in e)break;this.pop().release()}}pruneExceptNewestZ(){if(0!==this.getCount()){var e=this.peekFirstKey();const t=fromKey(e)[0];this.forEach(function(e){e.tileCoord[0]!==t&&(this.remove(getKey(e.tileCoord)),e.release())}.bind(this))}}}export default TileCache;